  "inlineSchema": "// SES Match — data model\n// Modeled after the AISES \"自社保有人材 / 案件\" domain (rebuilt from scratch).\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ---------- Tenancy ----------\n\nmodel Organization {\n  id        String   @id @default(cuid())\n  name      String\n  slug      String   @unique\n  createdAt DateTime @default(now())\n\n  users    User[]\n  talents  Talent[]\n  projects Project[]\n}\n\nenum Role {\n  ADMIN\n  MEMBER\n}\n\nmodel User {\n  id    String @id @default(cuid())\n  orgId String\n  name  String\n  email String @unique\n  role  Role   @default(MEMBER)\n\n  org              Organization @relation(fields: [orgId], references: [id], onDelete: Cascade)\n  assignedTalents  Talent[]     @relation(\"TalentAssignee\")\n  assignedProjects Project[]    @relation(\"ProjectAssignee\")\n}\n\n// ---------- Shared enums ----------\n\nenum TalentType {\n  INHOUSE // 自社保有人材\n  PARTNER // 協力会社\n}\n\nenum DataSource {\n  REGISTER // 直登録\n  EMAIL // メール取り込み\n}\n\nenum TalentStatus {\n  NONE\n  PROPOSING // 提案中\n  ACTIVE // 稼働中\n  CLOSED // クローズ\n}\n\nenum ProjectStatus {\n  OPEN // 募集中\n  PROPOSING // 提案中\n  DECIDED // 決定\n  CLOSED // クローズ\n}\n\nenum Gender {\n  MALE\n  FEMALE\n  OTHER\n}\n\nenum EmploymentType {\n  EMPLOYEE // 社員\n  FREELANCE // 個人事業主 / フリーランス\n}\n\nenum Nationality {\n  JAPAN\n  OTHER\n}\n\nenum LanguageLevel {\n  NATIVE // ネイティブ\n  BUSINESS // ビジネス\n  DAILY // 日常会話\n  NONE\n}\n\n// 8-step remote preference, matching the source UI\nenum RemotePreference {\n  FULL_REMOTE // フルリモート\n  MOSTLY_REMOTE // 基本リモート\n  HYBRID // ハイブリッド\n  OFFICE_1 // 週1回出社可\n  OFFICE_2 // 週2回出社可\n  OFFICE_3 // 週3回出社可\n  OFFICE_4 // 週4回出社可\n  ONSITE // 常駐可\n}\n\n// ---------- Talent (人材) ----------\n\nmodel Talent {\n  id           String       @id @default(cuid())\n  orgId        String\n  managementId String? // 管理ID\n  talentType   TalentType   @default(INHOUSE)\n  dataFrom     DataSource   @default(REGISTER)\n  status       TalentStatus @default(NONE)\n\n  assigneeId  String?\n  name        String\n  age         Int?\n  gender      Gender?\n  affiliation String? // 所属（例: 弊社個人事業主）\n\n  employmentType EmploymentType?\n  nationality    Nationality?\n  japaneseLevel  LanguageLevel?\n  englishLevel   LanguageLevel?\n\n  // 稼働開始\n  availabilityText String? // 例: \"即日or6月〜\"\n  availabilityDate DateTime?\n\n  // 月額報酬（万円）\n  desiredRateMin Int?\n  desiredRateMax Int?\n\n  remotePreference RemotePreference?\n  nearestStation   String?\n\n  // multi-value attributes\n  mainSkills     String[] @default([])\n  skills         String[] @default([])\n  qualifications String[] @default([])\n  tags           String[] @default([])\n\n  emailSubject String? // メール件名（メール取り込み時）\n  note         String?\n  receivedDate DateTime @default(now()) // 配信日\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  org         Organization @relation(fields: [orgId], references: [id], onDelete: Cascade)\n  assignee    User?        @relation(\"TalentAssignee\", fields: [assigneeId], references: [id])\n  attachments Attachment[]\n  matches     Match[]\n\n  @@index([orgId, talentType, status])\n}\n\nmodel Attachment {\n  id       String @id @default(cuid())\n  talentId String\n  filename String\n  url      String\n\n  talent Talent @relation(fields: [talentId], references: [id], onDelete: Cascade)\n}\n\n// ---------- Project (案件) ----------\n\nmodel Project {\n  id           String        @id @default(cuid())\n  orgId        String\n  managementId String?\n  title        String\n  clientName   String? // エンド / 商流元\n  businessFlow String? // 商流\n  status       ProjectStatus @default(OPEN)\n  dataFrom     DataSource    @default(REGISTER)\n\n  assigneeId  String?\n  description String?\n\n  requiredSkills String[] @default([])\n  tags           String[] @default([])\n\n  rateMin Int?\n  rateMax Int?\n\n  remotePreference RemotePreference?\n  location         String?\n  nearestStation   String?\n\n  startText String?\n  startDate DateTime?\n\n  receivedDate DateTime @default(now())\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  org      Organization @relation(fields: [orgId], references: [id], onDelete: Cascade)\n  assignee User?        @relation(\"ProjectAssignee\", fields: [assigneeId], references: [id])\n  matches  Match[]\n\n  @@index([orgId, status])\n}\n\n// ---------- Matching ----------\n\nmodel Match {\n  id        String   @id @default(cuid())\n  talentId  String\n  projectId String\n  score     Float    @default(0)\n  reasons   String[] @default([])\n  createdAt DateTime @default(now())\n\n  talent  Talent  @relation(fields: [talentId], references: [id], onDelete: Cascade)\n  project Project @relation(fields: [projectId], references: [id], onDelete: Cascade)\n\n  @@unique([talentId, projectId])\n}\n",
